CREATE TABLE `licencia_construccion` (
  `id` int NOT NULL AUTO_INCREMENT,
  `cod_municipio` varchar(3) DEFAULT NULL,
  `año_licencia` int DEFAULT NULL,
  `mes_licencia` bigint DEFAULT NULL,
  `estrato_licencia` int DEFAULT NULL,
  `area_m2_licencia` decimal(10,2) DEFAULT NULL,
  `unidades_vivienda_licencia` int DEFAULT NULL,
  `licencias` int DEFAULT NULL,
  `clase_suelo` varchar(9) NOT NULL DEFAULT '',
  `tipo_vivienda` varchar(12) NOT NULL DEFAULT '',
  `subsidio_licencia` varchar(12) NOT NULL DEFAULT '',
  PRIMARY KEY (`id`),
  KEY `fk_municipio` (`cod_municipio`),
  CONSTRAINT `fk_municipio` FOREIGN KEY (`cod_municipio`) REFERENCES `municipio` (`cod_muni`)
) ENGINE=InnoDB AUTO_INCREMENT=2794 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
